1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 0.1;
3	
4	interface QuoteStep {
5	  op: "quote";
6	  items: { type: string }[];
7	}
8	
9	interface Scenario {
10	  customer: { yearsWithMHPCO: number };
11	  steps: QuoteStep[];
12	}
13	
14	const BASE_PREMIUMS: Record<string, number> = {
15	  sword: 100,
16	};
17	
18	const quotePremium = (step: QuoteStep): number => {
19	  let premium = 0;
20	  for (const item of step.items) {
21	    const base = BASE_PREMIUMS[item.type];
22	    premium += base * (1 + FIRST_INSURANCE_SURCHARGE);
23	  }
24	  const total = premium + PROCESSING_FEE;
25	  return Math.ceil(Number(total.toFixed(6)));
26	};
27	
28	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
29	  return { results: scenario.steps.map((step) => ({ premium: quotePremium(step) })) };
30	};
