const quotePremium = (step: QuoteStep): number => {
  const itemsPremium = step.items.reduce(
    (sum, item) => sum + BASE_PREMIUMS[item.type] * (1 + FIRST_INSURANCE_SURCHARGE),
    0,
  );
  const total = itemsPremium + PROCESSING_FEE;
  return Math.ceil(Number(total.toFixed(6)));
};
